import{c as o,a7 as s,y as t,B as e}from"./chunks/framework.3cjvm90C.js";const d=JSON.parse('{"title":"Focal Loss","description":"Focal Loss 损失函数在目标检测中的原理与应用","frontmatter":{"title":"Focal Loss","description":"Focal Loss 损失函数在目标检测中的原理与应用"},"headers":[],"relativePath":"dlwiki/object-detection/focal_loss.md","filePath":"dlwiki/object-detection/focal_loss.md","lastUpdated":1782456021000}'),l={name:"dlwiki/object-detection/focal_loss.md"};function c(p,a,n,r,i,g){return s(),t("div",null,[...a[0]||(a[0]=[e('<h2 id="focal-loss" tabindex="-1">Focal Loss <a class="header-anchor" href="#focal-loss" aria-label="Permalink to “Focal Loss”">​</a></h2><p><strong>那么就要找 one-stage detector 的准确率不如 two-stage detector 的原因，作者认为原因是：样本的类别不均衡导致的</strong>。我们知道在 object detection 领域，一张图像可能生成成千上万的 candidate locations，但是其中只有很少一部分是包含 object 的，这就带来了类别不均衡。那么类别不均衡会带来什么后果呢？引用原文讲的两个后果：</p><p><strong>负样本数量太大，占总的 loss 的大部分，而且多是容易分类的，因此使得模型的优化方向并不是我们所希望的那样</strong>。其实先前也有一些算法来处理类别不均衡的问题，比如 OHEM, <strong>OHEM 算法虽然增加了错分类样本的权重，但是 OHEM 算法忽略了容易分类的样本。</strong></p><p>因此针对类别不均衡问题，作者提出一种新的损失函数：focal loss，这个损失函数是在标准交叉熵损失基础上修改得到的。<strong>这个函数可以通过减少易分类样本的权重，使得模型在训练时更专注于难分类的样本。</strong>为了证明 focal loss 的有效性，作者设计了一个 dense detector：RetinaNet，并且在训练时采用 focal loss 训练。<strong>实验证明 RetinaNet 不仅可以达到 one-stage detector 的速度，也能有 two-stage detector 的准确率。</strong></p><h3 id="_1-总述" tabindex="-1">1. 总述 <a class="header-anchor" href="#_1-总述" aria-label="Permalink to “1. 总述”">​</a></h3><p>Focal Loss 主要是为了解决 one-stage 目标检测中正负样本比例严重失衡的问题。该损失函数降低了大量简单负样本在训练中所占的权重，也可理解为一种困难样本挖掘。</p><h3 id="_2-损失函数形式" tabindex="-1">2. 损失函数形式 <a class="header-anchor" href="#_2-损失函数形式" aria-label="Permalink to “2. 损失函数形式”">​</a></h3><p>Focal Loss 是在交叉熵损失函数基础上进行的修改，首先回顾二分类交叉熵损失：</p><p><img src="https://images2018.cnblogs.com/blog/1055519/201808/1055519-20180818162755861-24998254.png" alt="img"></p><p><img src="https://images2018.cnblogs.com/blog/1055519/201808/1055519-20180818162835223-1945881125.png" alt="img">是经过激活函数的输出，所以在 0-1 之间。可见普通的交叉熵对于正样本而言，输出概率越大损失越小。对于负样本而言，输出概率越小则损失越小。此时的损失函数在大量简单样本的迭代过程中比较缓慢且可能无法优化至最优。那么 Focal loss 是怎么改进的呢？</p><p><img src="https://images2018.cnblogs.com/blog/1055519/201808/1055519-20180818174822290-765890427.png" alt="img"></p><p><img src="https://images2018.cnblogs.com/blog/1055519/201808/1055519-20180818170840882-453549240.png" alt="img"></p><p>首先在原有的基础上加了一个因子，其中 gamma&gt;0 使得减少易分类样本的损失。使得更关注于困难的、错分的样本。</p><p>例如 gamma 为 2，对于正类样本而言，预测结果为 0.95 肯定是简单样本，所以（1-0.95）的 gamma 次方就会很小，这时损失函数值就变得更小。而预测概率为 0.3 的样本其损失相对很大。对于负类样本而言同样，预测 0.1 的结果应当远比预测 0.7 的样本损失值要小得多。对于预测概率为 0.5 时，损失只减少了 0.25 倍，所以更加关注于这种难以区分的样本。这样减少了简单样本的影响，大量预测概率很小的样本叠加起来后的效应才可能比较有效。</p><p>此外，加入平衡因子 alpha，用来平衡正负样本本身的比例不均：文中 alpha 取 0.25，即正样本要比负样本占比小，这是因为负例易分。</p><p><img src="https://images2018.cnblogs.com/blog/1055519/201808/1055519-20180818174944824-933422059.png" alt="img"></p><p>只添加 alpha 虽然可以平衡正负样本的重要性，但是无法解决简单与困难样本的问题。</p><p>gamma 调节简单样本权重降低的速率，当 gamma 为 0 时即为交叉熵损失函数，当 gamma 增加时，调整因子的影响也在增加。实验发现 gamma 为 2 是最优。</p><p>直觉上来说，调制因子减少了易分样本的损失贡献，拓宽了样例接收到低损失的范围。当γ一定的时候，比如等于 2，一样 easy example(pt=0.9)的 loss 要比标准的交叉熵 loss 小 100+倍，当 pt=0.968 时，要小 1000+倍，但是对于 hard example(pt &lt; 0.5)，loss 最多小了 4 倍。这样的话 hard example 的权重相对就提升了很多。这样就增加了那些误分类的重要性</p><h3 id="_3-总结" tabindex="-1">3. 总结 <a class="header-anchor" href="#_3-总结" aria-label="Permalink to “3. 总结”">​</a></h3><p>作者认为 one-stage 和 two-stage 的表现差异主要原因是大量前景背景类别不平衡导致。作者设计了一个简单密集型网络 RetinaNet 来训练在保证速度的同时达到了精度最优。在双阶段算法中，在候选框阶段，通过得分和 nms 筛选过滤掉了大量的负样本，然后在分类回归阶段又固定了正负样本比例，或者通过 OHEM 在线困难挖掘使得前景和背景相对平衡。而 one-stage 阶段需要产生约 100k 的候选位置，虽然有类似的采样，但是训练仍然被大量负样本所主导。</p>',21)])])}const h=o(l,[["render",c]]);export{d as __pageData,h as default};
